const question = $.input.question;
const domains = ($.input.domains || 'academic, industry, news').split(',').map(d => d.trim()).filter(Boolean);
const queries = domains.map(domain => {
  let prefix = '';
  if (domain === 'academic') prefix = 'research paper findings about ';
  else if (domain === 'industry') prefix = 'industry analysis and business perspective on ';
  else if (domain === 'news') prefix = 'latest news and developments about ';
  else if (domain === 'technical') prefix = 'technical documentation and implementation of ';
  else prefix = domain + ' perspective on ';
  return { domain, query: prefix + question };
});
return { queries, domainCount: queries.length };

const queries = $.steps.buildQueries.output.queries;
const iterations = $.steps.searchDomains.response.iterations || [];

let compiled = '';
let totalSources = 0;
const domainResults = [];

queries.forEach((q, i) => {
  const iter = iterations[i];
  const results = (iter && iter.searchDomain && iter.searchDomain.response && iter.searchDomain.response.results) ? iter.searchDomain.response.results : [];
  compiled += '=== DOMAIN: ' + q.domain.toUpperCase() + ' (' + results.length + ' sources) ===\n';
  results.forEach((r, j) => {
    compiled += (j + 1) + '. ' + (r.title || 'Untitled') + '\n';
    compiled += '   URL: ' + (r.url || '') + '\n';
    compiled += '   ' + (r.text || '').slice(0, 1200) + '\n\n';
    totalSources++;
  });
  compiled += '\n';
  domainResults.push({ domain: q.domain, sourceCount: results.length });
});

return { compiled: compiled.slice(0, 30000), totalSources, domainResults };

const d = $.steps.compileSources.output;
const question = $.input.question;

let prompt = 'You are an expert research synthesizer that combines information from multiple knowledge domains (like a GraphRAG system). Your job is to cross-reference findings across domains to produce a comprehensive, well-sourced answer.\n\n';
prompt += 'RESEARCH QUESTION: ' + question + '\n\n';
prompt += 'KNOWLEDGE BASE (' + d.totalSources + ' sources across ' + d.domainResults.length + ' domains):\n';
prompt += d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Synthesize findings across all domains into a coherent answer\n';
prompt += '- Identify where domains agree, disagree, or complement each other\n';
prompt += '- Cite sources by [Domain: Source #] notation\n';
prompt += '- Highlight cross-domain connections and insights\n';
prompt += '- Flag any gaps or areas needing further research\n';
prompt += '- Use Slack mrkdwn: *bold* (NOT **bold**), _italic_, numbered lists\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "synthesizedAnswer": "comprehensive answer citing [Domain: #] sources in Slack mrkdwn",\n';
prompt += '  "confidence": "high|medium|low",\n';
prompt += '  "domainBreakdown": [{ "domain": "name", "keyFindings": ["finding1"], "reliability": "high|medium|low" }],\n';
prompt += '  "crossDomainInsights": ["insight where multiple domains intersect"],\n';
prompt += '  "knowledgeGaps": ["areas where more research is needed"],\n';
prompt += '  "followUpQuestions": ["suggested next question"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiSynthesis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { synthesizedAnswer: raw, confidence: 'medium', domainBreakdown: [], crossDomainInsights: [], knowledgeGaps: [], followUpQuestions: [] }; }

const ai = $.steps.parseAI.output;
const d = $.steps.compileSources.output;
const confidenceEmoji = ai.confidence === 'high' ? ':large_green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Multi-Domain Research Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + $.input.question } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: confidenceEmoji + ' *Confidence:* ' + (ai.confidence || 'medium') + ' | *Sources:* ' + d.totalSources + ' across ' + d.domainResults.length + ' domains' } });
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: (ai.synthesizedAnswer || 'No synthesis generated.').slice(0, 2900) } });
blocks.push({ type: 'divider' });

if (ai.crossDomainInsights && ai.crossDomainInsights.length > 0) {
  let crossText = '*Cross-Domain Insights:*\n';
  ai.crossDomainInsights.forEach((ins, i) => { crossText += (i + 1) + '. ' + ins + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: crossText.slice(0, 1800) } });
  blocks.push({ type: 'divider' });
}

if (ai.knowledgeGaps && ai.knowledgeGaps.length > 0) {
  let gapText = '*Knowledge Gaps:*\n';
  ai.knowledgeGaps.forEach((g, i) => { gapText += (i + 1) + '. ' + g + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: gapText.slice(0, 1800) } });
}

if (ai.followUpQuestions && ai.followUpQuestions.length > 0) {
  let fqText = '*Suggested Follow-ups:*\n';
  ai.followUpQuestions.forEach((q, i) => { fqText += (i + 1) + '. ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fqText.slice(0, 1800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa Multi-Domain Search + Claude AI | One CLI' }] });
const fallback = 'Research Report: ' + (ai.synthesizedAnswer || '').slice(0, 100);
return { blocks, fallback };
